script.inlineScript:
import { readFileSync, writeFileSync } from 'fs';

const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const raw = input.steps?.['upload-data']?.payload || input.steps?.['fix-errors']?.payload || '';
const errors = [];

try {
  const data = JSON.parse(raw);
  if (!data.id) errors.push('Missing required field: id');
  if (!data.name) errors.push('Missing required field: name');
  if (data.value !== undefined && typeof data.value !== 'number') errors.push('Field "value" must be a number');
} catch (e) {
  errors.push(`Invalid JSON: ${e.message}`);
}

writeFileSync('/output/result.json', JSON.stringify({
  valid: errors.length === 0,
  errors,
  summary: errors.length === 0 ? 'Validation passed' : `${errors.length} error(s) found`
}));
